// 取得指定日期種子的固定隨機 10 字
function getDailyWords(dateStr, n = 10, learnedIds = []) {
  const unlearned = wordsPool.filter(w => !learnedIds.includes(w.id));
  const pool = unlearned.length >= n ? unlearned : wordsPool;
  return seededShuffle(pool, dateSeed(dateStr)).slice(0, n);
}

function dateSeed(dateStr) {
  let h = 0;
  for (let i = 0; i < dateStr.length; i++) {
    h = ((h << 5) - h) + dateStr.charCodeAt(i);
    h |= 0;
  }
  return Math.abs(h) + 1;
}

function seededShuffle(arr, seed) {
  const a = [...arr];
  let s = seed;
  for (let i = a.length - 1; i > 0; i--) {
    s = (s * 9301 + 49297) % 233280;
    const j = Math.floor((s / 233280) * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}
